import{_ as e,H as i,f as s,i as l}from"./chunks/framework.CzroR0Ng.js";const k=JSON.parse('{"title":"Codex 安装、配置与运行手册","description":"","frontmatter":{},"headers":[],"relativePath":"guide/codex-guide.md","filePath":"guide/codex-guide.md"}'),t={name:"guide/codex-guide.md"};function o(h,a,n,d,p,r){return i(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="codex-安装、配置与运行手册" tabindex="-1">Codex 安装、配置与运行手册 <a class="header-anchor" href="#codex-安装、配置与运行手册" aria-label="Permalink to &quot;Codex 安装、配置与运行手册&quot;">​</a></h1><p>本手册面向第一次接触 Codex 的同学，目标是让你在 10-20 分钟内完成安装并跑通一次完整流程。</p><h2 id="_1-codex-是什么" tabindex="-1">1. Codex 是什么 <a class="header-anchor" href="#_1-codex-是什么" aria-label="Permalink to &quot;1. Codex 是什么&quot;">​</a></h2><p>Codex 是一个 AI 编程助手工作环境，可以在本地项目中完成：</p><ul><li>代码阅读与重构</li><li>Bug 排查与修复</li><li>文档编写与维护</li><li>自动化脚本与工程化任务</li></ul><h2 id="_2-环境准备" tabindex="-1">2. 环境准备 <a class="header-anchor" href="#_2-环境准备" aria-label="Permalink to &quot;2. 环境准备&quot;">​</a></h2><p>在安装 Codex 前，请先确认：</p><ul><li>已安装 Git（用于代码仓库操作）</li><li>已安装 Node.js（建议 18+）</li><li>有可用的 OpenAI API Key</li></ul><p>你可以用以下命令检查：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><h2 id="_3-安装-codex" tabindex="-1">3. 安装 Codex <a class="header-anchor" href="#_3-安装-codex" aria-label="Permalink to &quot;3. 安装 Codex&quot;">​</a></h2><blockquote><p>说明：Codex 可能有 CLI 和桌面端两种形态，你可以按团队使用习惯选择。</p></blockquote><h3 id="_3-1-方式-a-使用-npm-全局安装-cli" tabindex="-1">3.1 方式 A：使用 npm 全局安装（CLI） <a class="header-anchor" href="#_3-1-方式-a-使用-npm-全局安装-cli" aria-label="Permalink to &quot;3.1 方式 A：使用 npm 全局安装（CLI）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">codex-cli-package-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>安装后验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><h3 id="_3-2-方式-b-桌面端安装" tabindex="-1">3.2 方式 B：桌面端安装 <a class="header-anchor" href="#_3-2-方式-b-桌面端安装" aria-label="Permalink to &quot;3.2 方式 B：桌面端安装&quot;">​</a></h3><ol><li>下载并安装 Codex Desktop。</li><li>首次启动后，选择本地工作目录（Workspace）。</li><li>在设置页完成 API 凭据绑定。</li></ol><h2 id="_4-配置-codex" tabindex="-1">4. 配置 Codex <a class="header-anchor" href="#_4-配置-codex" aria-label="Permalink to &quot;4. 配置 Codex&quot;">​</a></h2><h2 id="_4-1-配置-api-key-推荐环境变量" tabindex="-1">4.1 配置 API Key（推荐环境变量） <a class="header-anchor" href="#_4-1-配置-api-key-推荐环境变量" aria-label="Permalink to &quot;4.1 配置 API Key（推荐环境变量）&quot;">​</a></h2><h3 id="windows-powershell-当前会话" tabindex="-1">Windows PowerShell（当前会话） <a class="header-anchor" href="#windows-powershell-当前会话" aria-label="Permalink to &quot;Windows PowerShell（当前会话）&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENAI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你的_api_key&quot;</span></span></code></pre></div><h3 id="macos-linux-当前会话" tabindex="-1">macOS / Linux（当前会话） <a class="header-anchor" href="#macos-linux-当前会话" aria-label="Permalink to &quot;macOS / Linux（当前会话）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENAI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你的_api_key&quot;</span></span></code></pre></div><p>如果要持久化，请写入 shell 配置文件（如 <code>.bashrc</code>、<code>.zshrc</code>）。</p><h2 id="_4-2-常见配置项" tabindex="-1">4.2 常见配置项 <a class="header-anchor" href="#_4-2-常见配置项" aria-label="Permalink to &quot;4.2 常见配置项&quot;">​</a></h2><p>根据团队规范，你可能还会配置：</p><ul><li>默认模型（如通用模型、推理模型）</li><li>推理强度（reasoning effort）</li><li>默认工作目录（workspace）</li><li>输出语言（中文/英文）</li></ul><h2 id="_5-运行与基本使用" tabindex="-1">5. 运行与基本使用 <a class="header-anchor" href="#_5-运行与基本使用" aria-label="Permalink to &quot;5. 运行与基本使用&quot;">​</a></h2><h2 id="_5-1-在项目目录启动" tabindex="-1">5.1 在项目目录启动 <a class="header-anchor" href="#_5-1-在项目目录启动" aria-label="Permalink to &quot;5.1 在项目目录启动&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your-project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span></span></code></pre></div><h2 id="_5-2-常见使用流程" tabindex="-1">5.2 常见使用流程 <a class="header-anchor" href="#_5-2-常见使用流程" aria-label="Permalink to &quot;5.2 常见使用流程&quot;">​</a></h2><ol><li>先让 Codex 熟悉项目：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>熟悉一下这个项目</span></span></code></pre></div><ol start="2"><li>提具体任务：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我定位登录模块的状态管理问题并修复</span></span></code></pre></div><ol start="3"><li>让 Codex 验证结果：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>跑一下测试并告诉我失败原因</span></span></code></pre></div><ol start="4"><li>最后让它总结变更：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>总结一下你改了哪些文件，风险点是什么</span></span></code></pre></div><h2 id="_6-推荐工作习惯" tabindex="-1">6. 推荐工作习惯 <a class="header-anchor" href="#_6-推荐工作习惯" aria-label="Permalink to &quot;6. 推荐工作习惯&quot;">​</a></h2><ul><li>给明确目标：功能、范围、约束条件一次说清</li><li>让它“先读后改”：先梳理上下文，再动代码</li><li>每次改动后都做验证：构建、测试、关键路径回归</li><li>大改动分步骤进行：避免一次改太多难以回滚</li></ul><h2 id="_7-常见问题排查" tabindex="-1">7. 常见问题排查 <a class="header-anchor" href="#_7-常见问题排查" aria-label="Permalink to &quot;7. 常见问题排查&quot;">​</a></h2><h2 id="_7-1-命令不可用" tabindex="-1">7.1 命令不可用 <a class="header-anchor" href="#_7-1-命令不可用" aria-label="Permalink to &quot;7.1 命令不可用&quot;">​</a></h2><p>现象：<code>codex</code> 或 <code>npm</code> 无法执行。<br> 处理：检查 PATH、终端权限、PowerShell 执行策略。</p><h2 id="_7-2-api-key-无效" tabindex="-1">7.2 API Key 无效 <a class="header-anchor" href="#_7-2-api-key-无效" aria-label="Permalink to &quot;7.2 API Key 无效&quot;">​</a></h2><p>现象：请求认证失败。<br> 处理：确认 Key 是否有效、是否有多余空格、环境变量是否生效。</p><h2 id="_7-3-依赖安装失败" tabindex="-1">7.3 依赖安装失败 <a class="header-anchor" href="#_7-3-依赖安装失败" aria-label="Permalink to &quot;7.3 依赖安装失败&quot;">​</a></h2><p>现象：<code>npm install</code> 超时或报网络错误。<br> 处理：检查网络代理设置，必要时切换 npm registry。</p><h2 id="_7-4-构建通过但页面异常" tabindex="-1">7.4 构建通过但页面异常 <a class="header-anchor" href="#_7-4-构建通过但页面异常" aria-label="Permalink to &quot;7.4 构建通过但页面异常&quot;">​</a></h2><p>处理：检查路由 <code>base</code>、静态资源路径和部署目录是否一致。</p><h2 id="_8-团队协作建议" tabindex="-1">8. 团队协作建议 <a class="header-anchor" href="#_8-团队协作建议" aria-label="Permalink to &quot;8. 团队协作建议&quot;">​</a></h2><ul><li>把高频提示词沉淀为模板（例如“修复 bug 模板”）</li><li>在 PR 描述中附上 Codex 改动摘要</li><li>关键模块开启 Code Review，不直接跳过人工确认</li></ul><h2 id="_9-快速检查清单" tabindex="-1">9. 快速检查清单 <a class="header-anchor" href="#_9-快速检查清单" aria-label="Permalink to &quot;9. 快速检查清单&quot;">​</a></h2><ul><li>[ ] 已安装并能执行 <code>codex --version</code></li><li>[ ] 已配置 <code>OPENAI_API_KEY</code></li><li>[ ] 能在项目目录启动 Codex</li><li>[ ] 能完成一次“读代码 -&gt; 改代码 -&gt; 验证”的闭环</li></ul><p>完成以上四项后，你就可以把 Codex 稳定纳入日常开发流程。</p>`,56)])])}const u=e(t,[["render",o]]);export{k as __pageData,u as default};
